// apply-usfi-update.js
// Self-contained installer -- no zip, no extraction, no copying.
// Writes two files directly into place (backing up the current ones):
//   fetch-data.js        -> v2 tackle coverage (boxscore ids + name aliases)
//   public/index.html    -> Defense-tab Tkl/Tk% columns, tackles podium,
//                           tackles integrated into defense grading,
//                           AND restores option-A tokens (the legibility
//                           patch that slipped onto main is undone).
// Run from repo root:  node apply-usfi-update.js
// Then:                node fetch-data.js   (regenerates cache at ~590 tackle coverage)

const fs=require("fs");
if(!fs.existsSync("public/index.html")||!fs.existsSync("fetch-data.js")){
  console.log("\u274C Run this from the repo root (usa-footy-index).");process.exit(1);
}
const FD=Buffer.from("","base64");
const IDX=Buffer.from("","base64");

fs.copyFileSync("fetch-data.js","fetch-data.js.bak");
fs.copyFileSync("public/index.html","public/index.html.bak");
fs.writeFileSync("fetch-data.js",FD);
fs.writeFileSync("public/index.html",IDX);
console.log("\u2705 fetch-data.js written ("+FD.length+" bytes, backup: fetch-data.js.bak)");
console.log("\u2705 public/index.html written ("+IDX.length+" bytes, backup: public/index.html.bak)");
console.log("\nNow rebuild the cache with the new fetcher (takes ~5-10 min):");
console.log("  node fetch-data.js");
console.log("\nThen ship (run separately):");
console.log("  git add fetch-data.js public/index.html public/data public/headshots");
console.log('  git commit -m "Tackles v2 coverage + Defense-tab columns + grading; restore A tokens"');
console.log("  git pull origin main --no-rebase");
console.log("  git push origin main");
console.log("\nAfter Cloudflare deploys, this should print ~590:");
console.log("  node -e \"const d=require('./public/data/mls-cache.json');console.log(d.players.filter(p=>(p.tk||0)>0).length)\"");
